    EXPECT_EQ(ctx->forkCtx.timer, nullptr);
    EXPECT_EQ(ctx->forkCtx.watcherHandle, nullptr);
    EXPECT_EQ(ctx->forkCtx.coldRunPath, nullptr);
    EXPECT_EQ(ctx->forkCtx.fd[0], -1);
    EXPECT_EQ(ctx->forkCtx.fd[1], -1);

